import java.io.*;
import org.owasp.html.Sanitizers;

public class XSSSecureCode {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = Sanitizers.BLOCKS_ALWAYS_ALLOWED_HTML.apply(userInput);

        // Properly handling user input by sanitizing it before outputting it to a HTML file
        try {
            BufferedWriter writer = new BufferedWriter(new FileWriter("output.html"));
            writer.write("<html><body>");
            writer.write(sanitizedInput);
            writer.write("</body></html>");
            writer.close();
            System.out.println("Successfully wrote sanitized output to file.");
        } catch (IOException e) {
            System.err.println("Error writing to file: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
